+const LIVE_RELOAD_SCRIPT: &str = r"<script>
+(() => {
+  let lastToken = null;
+  async function poll() {
+    try {
+      const resp = await fetch('/.bvr/livereload', { cache: 'no-store' });
+      const token = (await resp.text()).trim();
+      if (lastToken === null) {
+        lastToken = token;
+      } else if (token !== lastToken) {
+        window.location.reload();
+        return;
+      }
+    } catch (_) {}
+    setTimeout(poll, 1200);
+  }
+  poll();
+})();
+</script>";
